// =============================================================================
// adc_4ch — AD7476A Multi-Channel ADC Reader
// Generated by ice40-codegen peripheral system
//
// Channels:       4
// SCLK divider:   6 (3-bit counter)
// Sample period:  2400 clocks (12-bit counter)
// =============================================================================
`default_nettype none

module adc_4ch (
    input  wire clk,
    input  wire rst_n,
    input  wire enable,

    input  wire ch0_sdata,

    input  wire ch1_sdata,

    input  wire ch2_sdata,

    input  wire ch3_sdata,

    output wire cs_out,
    output wire sclk_out,

    output wire [11:0] ch0_data,

    output wire [11:0] ch1_data,

    output wire [11:0] ch2_data,

    output wire [11:0] ch3_data,

    output wire new_data
);

    localparam SCLK_DIV    = 6;
    localparam SAMPLE_PER  = 2400;

    // =========================================================================
    // State Machine
    // =========================================================================
    localparam S_IDLE    = 2'd0;
    localparam S_CONVERT = 2'd1;
    localparam S_LATCH   = 2'd2;

    reg [1:0] state;

    // =========================================================================
    // Counters and Registers
    // =========================================================================
    reg [11:0] sample_counter;
    reg [2:0]     sclk_counter;
    reg [4:0]                           bit_counter;    // counts 0..15 (16 bits)
    reg                                 sclk_reg;
    reg                                 cs_reg;
    reg                                 new_data_reg;


    reg [15:0] ch0_shift;
    reg [11:0] ch0_data_reg;

    reg [15:0] ch1_shift;
    reg [11:0] ch1_data_reg;

    reg [15:0] ch2_shift;
    reg [11:0] ch2_data_reg;

    reg [15:0] ch3_shift;
    reg [11:0] ch3_data_reg;


    assign cs_out   = cs_reg;
    assign sclk_out = sclk_reg;
    assign new_data = new_data_reg;

    assign ch0_data = ch0_data_reg;

    assign ch1_data = ch1_data_reg;

    assign ch2_data = ch2_data_reg;

    assign ch3_data = ch3_data_reg;


    // =========================================================================
    // Main State Machine
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state          <= S_IDLE;
            cs_reg         <= 1'b1;
            sclk_reg       <= 1'b1;       // CPOL=1: idle high
            new_data_reg   <= 1'b0;
            sample_counter <= SAMPLE_PER[11:0];
            sclk_counter   <= {3{1'b0}};
            bit_counter    <= 5'd0;

            ch0_shift    <= 16'd0;
            ch0_data_reg <= 12'd0;

            ch1_shift    <= 16'd0;
            ch1_data_reg <= 12'd0;

            ch2_shift    <= 16'd0;
            ch2_data_reg <= 12'd0;

            ch3_shift    <= 16'd0;
            ch3_data_reg <= 12'd0;

        end else begin
            // Default: clear one-clock pulse
            new_data_reg <= 1'b0;

            case (state)
                // =============================================================
                // IDLE: CS high, SCLK idle high, wait for sample period
                // =============================================================
                S_IDLE: begin
                    cs_reg   <= 1'b1;
                    sclk_reg <= 1'b1;
                    if (enable) begin
                        if (sample_counter == 0) begin
                            // Start conversion
                            state        <= S_CONVERT;
                            cs_reg       <= 1'b0;       // Assert CS
                            sclk_reg     <= 1'b1;       // SCLK starts high
                            sclk_counter <= SCLK_DIV[2:0];
                            bit_counter  <= 5'd0;

                            ch0_shift <= 16'd0;

                            ch1_shift <= 16'd0;

                            ch2_shift <= 16'd0;

                            ch3_shift <= 16'd0;

                        end else begin
                            sample_counter <= sample_counter - 1'b1;
                        end
                    end
                end

                // =============================================================
                // CONVERT: Generate SCLK, shift in data
                // SPI Mode 3: data sampled on rising edge, shifted on falling
                // =============================================================
                S_CONVERT: begin
                    if (sclk_counter == 0) begin
                        sclk_counter <= SCLK_DIV[2:0];
                        sclk_reg     <= ~sclk_reg;

                        if (sclk_reg == 1'b0) begin
                            // Rising edge of SCLK: sample SDATA

                            ch0_shift <= {ch0_shift[14:0], ch0_sdata};

                            ch1_shift <= {ch1_shift[14:0], ch1_sdata};

                            ch2_shift <= {ch2_shift[14:0], ch2_sdata};

                            ch3_shift <= {ch3_shift[14:0], ch3_sdata};

                            bit_counter <= bit_counter + 1'b1;

                            if (bit_counter == 5'd15) begin
                                // All 16 bits shifted in, go to LATCH
                                state <= S_LATCH;
                            end
                        end
                    end else begin
                        sclk_counter <= sclk_counter - 1'b1;
                    end
                end

                // =============================================================
                // LATCH: Atomically copy shift[11:0] to data registers
                // =============================================================
                S_LATCH: begin

                    ch0_data_reg <= ch0_shift[11:0];

                    ch1_data_reg <= ch1_shift[11:0];

                    ch2_data_reg <= ch2_shift[11:0];

                    ch3_data_reg <= ch3_shift[11:0];

                    new_data_reg   <= 1'b1;
                    cs_reg         <= 1'b1;       // Deassert CS
                    sclk_reg       <= 1'b1;       // Return SCLK to idle
                    sample_counter <= SAMPLE_PER[11:0];
                    state          <= S_IDLE;
                end

                default: state <= S_IDLE;
            endcase
        end
    end

endmodule
